<template>
  <LTPages
      :title="'定义操作列表格'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">基于element封装的基础表格和分页。可通过tableConfig.isHiddenSelection 为true 和 columnButton 设置表格可勾选和操作栏。
            操作栏按钮可通过设置isHiddenShow字段控制按钮是否显示和列表数据状态字段灵活切换按钮状态。
            状态枚举值 必须设置0、1，例如： 0 隐藏，1 显示。 详情参见：columnButton配置。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div>
          <LTTableForm
              v-if="tableConfig.tableRefresh"
              v-loading="tableConfig.tableLoading"
              :tableConfig="tableConfig"
              @tablePageForm="getTableForm"
          ></LTTableForm>
        </div>
        <!--2、代码展示-->
        <div class="zhb-title" style="margin-top: 20px;">代码展示</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTSearchForm1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTSearchForm2" title="javaScript"></codeCopy>

        <!--5、columnButton配置参数-->
        <div class="zhb-title">columnButton配置参数</div>
        <div class="zhb-subTitle">
          columnButton：表格操作栏按钮配置，可设置按钮的名称、图标、方法名、是否禁用、动态按钮等。

        </div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="columnButtonData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--4、tableConfig配置参数-->
        <div class="zhb-title">tableConfig配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableConfigData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>










      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      tableConfig: {
        tableRefresh: true,
        tableLoading: false,
        tableHead: [
          {
            label: '用户名称',
            prop: 'username',
          },
          {
            label: '是否管理员',
            prop: 'isAdminName',
          },
          {
            label: '手机号',
            prop: 'mobile',
          },
          {
            label: '部门',
            prop: 'dept',
          },
          {
            label: '进度',
            prop: 'progress',
            isProgress: true
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [
          {username: "李辛", isAdminName: '是', mobile: '15974856942', status: '0', statusName:'未启用',createTime: '2024-04-28 14:30'},
          {username: "姜磊", isAdminName: '否', mobile: '18255060105', status: '1', statusName:'启用', createTime: '2024-04-28 14:30'},
          {username: "冒慧敏", isAdminName: '否', mobile: '18547896584', status: '0', statusName:'未启用', createTime: '2024-04-28 14:30'},
        ],
        columnButton: [
          {
            label: "启用",
            isStatus:true,
            prop:'status',
            subLabel:'禁用',
            click: (row) => {
              var status = row.status == 0 ? '启用' : '禁用';
              this.$meaaage.success({
                type: 'info',
                message: '操作-'+status,
              });


            },
          },
          {
            label: "编辑",
            click: (row) => {
              console.log("编辑====================")
              this.$meaaage.success({
                message: "这是‘编辑’操作",
                showClose: true,
                duration: 1000,
              });
              console.log(row)
            },
          },
          {
            label: "删除",
            isHiddenShow:true,
            click: (row) => {
              console.log("删除====================")
              this.$meaaage.success({
                message: "这是‘删除’操作",
                showClose: true,
                duration: 1000,
              });
              console.log(row)
            },
          },
        ],
        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: false, // 是否隐藏勾选
        isHiddenIndex: false, // 是否隐藏序号
        total: 150,
        pageSize: 20,
        currentPage: 1,
      },
      mainCode: `<LTTableForm
            v-if="tableConfig.tableRefresh"
            v-loading="tableConfig.tableLoading"
            :tableConfig="tableConfig"
            @tablePageForm="getTableForm"
        ></LTTableForm>`,
      jsCode: `
export default {
  data() {
    return {
      tableConfig: {
        tableRefresh: true,
        tableLoading: false,
        tableHead: [
          {
            label: '用户名称',
            prop: 'username',
          },
          {
            label: '是否管理员',
            prop: 'isAdminName',
          },
          {
            label: '手机号',
            prop: 'mobile',
          },
          {
            label: '部门',
            prop: 'dept',
          },
          {
            label: '进度',
            prop: 'progress',
            isProgress: true
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [
          {username: "李辛", isAdminName: '是', mobile: '15974856942', status: '0', statusName:'未启用',createTime: '2024-04-28 14:30'},
          {username: "姜磊", isAdminName: '否', mobile: '18255060105', status: '1', statusName:'启用', createTime: '2024-04-28 14:30'},
          {username: "冒慧敏", isAdminName: '否', mobile: '18547896584', status: '0', statusName:'未启用', createTime: '2024-04-28 14:30'},
        ],
        columnButton: [
          {
            label: "启用",
            isStatus:true,
            prop:'status',
            subLabel:'禁用',
            click: (row) => {
              var status = row.status == 0 ? '启用' : '禁用';
              this.$meaaage.success({
                type: 'info',
                message: '操作-'+status,
              });


            },
          },
          {
            label: "编辑",
            click: (row) => {
              console.log("编辑====================")
              this.$meaaage.success({
                message: "这是‘编辑’操作",
                showClose: true,
                duration: 1000,
              });
              console.log(row)
            },
          },
          {
            label: "删除",
            isHiddenShow:true,
            click: (row) => {
              console.log("删除====================")
              this.$meaaage.success({
                message: "这是‘删除’操作",
                showClose: true,
                duration: 1000,
              });
              console.log(row)
            },
          },
        ],
        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: false, // 是否隐藏勾选
        isHiddenIndex: false, // 是否隐藏序号
        total: 150,
        pageSize: 20,
        currentPage: 1,
      },
    }
  },
  methods: {
    // 表格分页回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.$message.success({
        message: "这是‘分页跳转’操作",
        showClose: true,
        duration: 1000,
      });
    }
  }
}`,
      tableData: [
        {
          text1:'tableConfig',
          text2:'表格配置',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'@tablePageForm',
          text2:'获取分页变化数据',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'必填项',
        }
      ],
      tableConfigData: [
        {
          text1:'tableRefresh',
          text2:'是否显示表格组件',
          text3:'Boolean',
          text4:'---',
          text5:'true',
          text6:'必填项',
        },
        {
          text1:'tableLoading',
          text2:'刷新表格组件',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'tableHead',
          text2:'表格表头及其字段',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'tableData',
          text2:'表格数据',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'columnButton',
          text2:'表格操作栏按钮',
          text3:'Array',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'columnWidth',
          text2:'表格操作栏宽度',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'tableColWidth',
          text2:'表格列宽度',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'isHiddenSelection',
          text2:'是否隐藏勾选',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'isHiddenIndex',
          text2:'是否隐藏序号',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'isHiddenPage',
          text2:'是否隐藏分页',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'total',
          text2:'表格数据总数',
          text3:'Number',
          text4:'---',
          text5:'0',
          text6:'必填项',
        },
        {
          text1:'pageSize',
          text2:'每页表格显示条数',
          text3:'Number',
          text4:'---',
          text5:'20',
          text6:'必填项',
        },
        {
          text1:'currentPage',
          text2:'当前页',
          text3:'Number',
          text4:'---',
          text5:'1',
          text6:'必填项',
        }
      ],
      columnButtonData: [
        {
          text1:'label',
          text2:'按钮名称',
          text3:'Boolean',
          text4:'---',
          text5:'true',
          text6:'必填项',
        },
        {
          text1:'click',
          text2:'事件回调',
          text3:'Function',
          text4:'---',
          text5:'true',
          text6:'---',
        },
        {
          text1:'isHiddenShow',
          text2:'按钮显示隐藏',
          text3:'Boolean',
          text4:'---',
          text5:'true',
          text6:'为整个用户条件',
        },
        {
          text1:'isStatus',
          text2:'动态按钮',
          text3:'Boolean',
          text4:'---',
          text5:'true',
          text6:'必须同时配置prop、subLabel',
        },
        {
          text1:'prop',
          text2:'动态按钮的状态字段',
          text3:'Number',
          text4:'---',
          text5:'true',
          text6:'状态枚举值 必须设置0、1，例如： 0 隐藏，1 显示',
        },
        {
          text1:'subLabel',
          text2:'动态按钮的互斥名称',
          text3:'String',
          text4:'---',
          text5:'true',
          text6:'---',
        },
      ]
    }
  },
  methods: {
    // 表格分页回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.$message.success({
        message: "这是‘分页跳转’操作",
        showClose: true,
        duration: 1000,
      });
    }
  }
}
</script>


